import React, { useRef, useState } from "react";
// Import Swiper React components
import { Swiper, SwiperSlide } from "swiper/react";

// Import Swiper styles
import "swiper/css";
import "swiper/css/grid";
import "swiper/css/pagination";

import "../styles/slider.css";

import amsterdam from "../images/amsterdamimage.webp"
import birmingham from "../images/birminghamimage.jpg"
import brugge from "../images/bruggeimage.jpg"
import ibiza from "../images/ibizaimage.jpg"
import lisboa from "../images/lisboaimage.webp"
import londres from "../images/londresimage.jpg"
import paris from "../images/parisimage.jpg"
import sanpetersburgo from "../images/sanpetersburgoimage.jpg"
import sozhuo from "../images/sozhuoimage.jpg"
import venecia from "../images/veneciaimage.jpg"
import napoles from "../images/imagenapoles.jpg"
import roma from "../images/imageroma.jpg"

// import required modules
import { Grid, Pagination } from "swiper";

export default function Carousel() {
  let arrayImages = {amsterdam, birmingham, brugge, ibiza, lisboa, londres, paris, sanpetersburgo, sozhuo, venecia, napoles, roma}
  console.log(arrayImages);
  return (
    <>
      <Swiper
        slidesPerView={3}
        grid={{
          rows: 2,
        }}
        spaceBetween={30}
        pagination={{
          clickable: true,
        }}
        modules={[Grid, Pagination]}
        className="mySwiper"
      >
        {arrayImages.map()}
        <SwiperSlide>Slide 1</SwiperSlide>
      </Swiper>
    </>
  );
}
